#include<bits/stdc++.h>
using namespace std;
const int N = 2e5+5;
struct block{
    int l,r,cs;
}add,k;
int n,a[N],rmd;
bool v[N];
queue<block> q,p;//p 是临时合并用的
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)scanf("%d",&a[i]);
    a[n+1]=1-a[n];
    for(int i=2,st=1;i<=n+1;i++){
        if(a[i]!=a[i-1]){
            add.l=st,add.r=i-1,add.cs=a[i-1];
            //cout<<add.l<<"---->"<<add.r<<":"<<add.cs<<endl;
            st=i;
            q.push(add);
        }
    }//合并
    rmd=n;
    while(rmd>0){
        while(q.size()>0){
            add=q.front();
            q.pop();
            while(v[add.l]&&add.l<=add.r)add.l++;
            if(add.l>add.r)continue;//取空了
            printf("%d ",add.l);
            v[add.l++]=1,rmd--;//少了一个
            if(add.l>add.r)continue;//取空了
            p.push(add);//搁进去用来合并
        }
        printf("\n");
        while(p.size()>0){
            add=p.front();
            p.pop();
            while(p.size()>0){
                k=p.front();
                if(add.cs==k.cs){add.r=k.r;p.pop();}
                else break;
            }
            q.push(add);//重新把合并好的扔进去
        }
    }
    return 0;
}
